const querPedir = /quero|vou querer|p[e�]de|me manda|queria/.test(msg);

let texto;
if (querCardapio) {
  texto = `Aqui est� nosso card�pio ??\n${LINK_CARDAPIO}\n\nViu algo que gostou? Me fala que eu anoto o pedido ??`;
