} else {
  const primeiro = nome ? nome.split(' ')[0] : '';
  texto = primeiro
    ? `Fala, ${primeiro}! ?? Aqui � o Grill Central. Me diz o que vai querer que j� monto teu pedido ??`
    : `Fala! ?? Aqui � o Grill Central. Me diz o que vai querer que j� monto teu pedido ??`;
