// ??? NORMALIZE ????????????????????????????????????????????????????????????????
function normalizeText(text) {
  return (text || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/-/g, ' ')
    .replace(/[^\w\s]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

// ??? MENU SERVICE ?????????????????????????????????????????????????????????????
// TODO: PDV - trocar por: const PRODUTOS = await PDVAdapter.getProducts();
// --- MENU SERVICE: catalogo real via GET /api/menu (cache 5 min) ----------------
