const MENU_CACHE_TTL = 5 * 60 * 1000;
let PRODUCTS = [];
try {
  const now = Date.now();
  if (!staticData.menuCache || (now - (staticData.menuCache.ts || 0)) > MENU_CACHE_TTL) {
    const menuResp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://grillcardapio.com.br/api/menu',
      json: true,
    });
    const prods = [];
    for (const cat of (menuResp.categories || [])) {
      for (const p of (cat.products || [])) {
        if (p.isActive === false) continue;
        prods.push({
          id: p.id,
          name: p.name,
          price: Number(p.price),
          category: cat.name,
          searchable: normalizeText(p.name) + ' ' + normalizeText(p.description || ''),
        });
      }
    }
    if (prods.length > 0) {
      staticData.menuCache = { ts: now, products: prods };
      PRODUCTS = prods;
    } else {
      PRODUCTS = MOCK_PRODUCTS_FALLBACK;
    }
  } else {
    PRODUCTS = staticData.menuCache.products;
  }
} catch (_menuErr) {
  PRODUCTS = (staticData.menuCache && staticData.menuCache.products && staticData.menuCache.products.length > 0)
    ? staticData.menuCache.products
    : MOCK_PRODUCTS_FALLBACK;
}

const STOP_WORDS = new Set(['com','sem','para','uma','uns','por','que','tem','vai','pra','nao','sim','de','do','da','dos','das','e','a','o','ao','um','na','no','nos','nas']);

const MenuService = {
  findProductByText(text) {
    const t = normalizeText(text);
    if (!t) return null;
    const exact = PRODUCTS.find(p => normalizeText(p.name) === t);
    if (exact) return exact;
    const contained = PRODUCTS.find(p => { const n = normalizeText(p.name); return t.includes(n) || n.includes(t); });
    if (contained) return contained;
    const words = t.split(' ').filter(w => w.length > 2 && !STOP_WORDS.has(w));
    if (words.length === 0) return null;
    let best = null; let bestScore = 1;
    for (const p of PRODUCTS) {
      const n = normalizeText(p.name); const s = p.searchable || '';
      let score = 0;
      for (const w of words) {
        if (n === w || n.includes(w)) score += 3;
        else if (n.startsWith(w)) score += 2;
        else if (s.includes(w)) score += 1;
      }
      if (score > bestScore) { bestScore = score; best = p; }
    }
    return best;
  },
  findSimilarProducts(text) {
    const t = normalizeText(text);
    const words = t.split(' ').filter(w => w.length > 2 && !STOP_WORDS.has(w));
    if (words.length === 0) return PRODUCTS.slice(0, 3);
    return PRODUCTS.filter(p => {
      const n = normalizeText(p.name); const s = p.searchable || '';
      return words.some(w => n.includes(w) || s.includes(w));
    }).slice(0, 3);
  },
  getProductById(id) { return PRODUCTS.find(p => p.id === id) || null; },
  listActiveProducts() { return PRODUCTS; },
  calculateItemsTotal(items) { return items.reduce((sum, i) => sum + (i.subtotal || 0), 0); },
};
const MOCK_TO_REAL_ID = {
  'xs001':67,'xc001':68,'xcal001':69,'xcos001':70,'xb001':71,
  'xfm001':72,'xa001':73,'xf001':74,
  'pan001':83,'pan002':84,'pan003':85,
  'batm001':92,'batg001':93,'batbm001':94,'batbg001':95,
  'cer001':96,'cer002':97,'ref001':98,'ref002':99,'ref003':100,'agua001':101,
};
function normalizePhone(raw) {
  let p = String(raw || '').replace(/\D/g, '');
  if (p.startsWith('55') && (p.length === 12 || p.length === 13)) p = p.slice(2);
  return p;
}

// ??? HELPERS ?????????????????????????????????????????????????????????????????
function extractQuantity(text) {
  const t = normalizeText(text);
  if (/\bmais (um|uma)\b/.test(t)) return 1;
  const numWords = { 'um': 1, 'uma': 1, 'dois': 2, 'duas': 2, 'tres': 3, 'quatro': 4, 'cinco': 5, 'seis': 6 };
  const nm = t.match(/(\d+)\s*x\s/) || t.match(/^(\d+)\s/) || t.match(/\s(\d+)\s*x?\s/);
  if (nm) return Math.max(1, Math.min(parseInt(nm[1]), 20));
  const words = t.split(' ');
  for (const [w, n] of Object.entries(numWords)) {
    if (words[0] === w || words.includes(w)) return n;
  }
  return 1;
}

function extractObservations(text) {
  const obs = [];
  const patterns = [
    /\bsem\s+\w+/gi,
    /\btirar\s+\w+/gi,
    /\bbem\s+passad[oa]/gi,
    /\bao\s+ponto/gi,
    /\bmal\s+passad[oa]/gi,
  ];
  for (const pat of patterns) {
    const found = text.match(pat) || [];
    obs.push(...found.map(o => o.trim()));
  }
  return [...new Set(obs)];
}

function addItemToOrder(orderState, product, quantity, observations) {
  const obsKey = [...observations].sort().join('|');
  const existing = orderState.items.find(
    i => i.productId === product.id && [...i.observations].sort().join('|') === obsKey
  );
  if (existing) {
    existing.quantity += quantity;
    existing.subtotal = existing.unitPrice * existing.quantity;
  } else {
    orderState.items.push({
      productId: product.id, name: product.name, quantity,
      unitPrice: product.price, observations, subtotal: product.price * quantity
    });
  }
  orderState.itemsTotal = MenuService.calculateItemsTotal(orderState.items);
}

function notFoundReply(text) {
  const similar = MenuService.findSimilarProducts(text);
  if (similar.length > 0) {
    return 'Esse n�o temos, mas temos ' + similar.map(p => p.name).join(' e ') + ' ?? Quer algum desses?';
  }
  return 'Hmm, n�o encontrei esse item. D� uma olhada no card�pio ??\n' + LINK_CARDAPIO + '\nMe fala o que vai querer!';
}

function fmtR(v) { return 'R$ ' + v.toFixed(2).replace('.', ','); }

function buildSummary(os) {
  let itens = '';
  for (const item of os.items) {
    const obs = item.observations.length ? ' (' + item.observations.join(', ') + ')' : '';
    itens += item.quantity + 'x ' + item.name + obs + ' - ' + fmtR(item.subtotal) + '\n';
  }
  const total = fmtR(os.itemsTotal);
  let entrega = '';
  if (os.deliveryType === 'delivery') {
    const end = os.address || (os.gpsLocation ? 'GPS ' + os.gpsLocation.lat + ',' + os.gpsLocation.lng : 'a confirmar');
    entrega = 'Entrega: ' + end + '\n';
  } else {
    entrega = 'Retirada no local ??\n';
  }
  const pgto = os.paymentMethod ? 'Pagamento: ' + os.paymentMethod + '\n' : '';
  const frete = os.deliveryType === 'delivery' ? ' + frete' : '';
  return 'Ficou assim ??\n' + itens + entrega + pgto + 'Total: ' + total + frete;
}

function newOS() {
  return { items: [], deliveryType: null, address: null, gpsLocation: null,
           paymentMethod: null, changeFor: null, itemsTotal: 0, deliveryFee: 0, grandTotal: 0, status: 'draft' };
}

// ??? MEM�RIA ?????????????????????????????????????????????????????????????????
