  memoria[numero] = { estado: 'inicio', ultima_intencao: null, etapa: 'nova_conversa',
    orderState: newOS(), lastItemAdded: null, ultima_interacao: Date.now() };
}
const cliente = memoria[numero];
cliente.ultima_interacao = Date.now();
if (!cliente.orderState) cliente.orderState = newOS();
if (!('lastItemAdded' in cliente)) cliente.lastItemAdded = null;

// ENCERRAMENTO
if (/obrigad|tchau|valeu|at[e�] logo|flw|at[e�] mais|xau/.test(msg)) {
  if (sessao) { sessao.historico = []; sessao.estado = 'inicio'; }
  memoria[numero] = { estado: 'inicio', ultima_intencao: null, etapa: 'nova_conversa',
    orderState: newOS(), lastItemAdded: null, ultima_interacao: Date.now() };
  const dp = ['Disponha! ?? Qualquer coisa � s� chamar.', 'At� logo! Volte sempre ??', 'Foi um prazer! ??'];
  return [{ json: { ...dados, textoResposta: dp[Math.floor(Math.random() * dp.length)], chamarLLM: false } }];
}

// ??? OBSERVA��O SEM PRODUTO (aplicar ao �ltimo item) ?????????????????????????
if (
  (cliente.etapa === 'aguardando_complemento' || cliente.etapa === 'aguardando_item') &&
  cliente.lastItemAdded && !MenuService.findProductByText(msg)
) {
  const obs = extractObservations(msgOrig);
  if (obs.length > 0) {
    const last = cliente.orderState.items.find(i => i.productId === cliente.lastItemAdded);
    if (last) {
      last.observations.push(...obs.filter(o => !last.observations.includes(o)));
      return [{ json: { ...dados, textoResposta: 'Anotado: ' + obs.join(', ') + ' no ' + last.name + ' ?\nMais alguma coisa?', chamarLLM: false } }];
    }
  }
}

// ??? FLUXO DE PEDIDO ?????????????????????????????????????????????????????????

if (cliente.etapa === 'aguardando_item') {
  const quantity = extractQuantity(msgOrig);
  const product = MenuService.findProductByText(msg);
  const observations = extractObservations(msgOrig);
  if (product) {
    addItemToOrder(cliente.orderState, product, quantity, observations);
    cliente.lastItemAdded = product.id;
    cliente.etapa = 'aguardando_complemento';
    const obsText = observations.length ? ' (' + observations.join(', ') + ')' : '';
    return [{ json: { ...dados, textoResposta: 'Anotado: ' + quantity + 'x ' + product.name + obsText + ' ??\nQuer adicionar alguma bebida ou acompanhamento?', chamarLLM: false } }];
  }
  return [{ json: { ...dados, textoResposta: notFoundReply(msg), chamarLLM: false } }];
}

if (cliente.etapa === 'aguardando_complemento') {
  if (/n[�a]o|s[�o] isso|pode fechar|sem mais|t[�a] [�o]timo|t[�a] bom|pode|fechou/.test(msg)) {
    cliente.etapa = 'aguardando_tipo_entrega';
    return [{ json: { ...dados, textoResposta: 'Certo! ?? Vai ser entrega ou voc� retira aqui?', chamarLLM: false } }];
  }
  const quantity = extractQuantity(msgOrig);
  const product = MenuService.findProductByText(msg);
  const observations = extractObservations(msgOrig);
  if (product) {
    addItemToOrder(cliente.orderState, product, quantity, observations);
    cliente.lastItemAdded = product.id;
    const obsText = observations.length ? ' (' + observations.join(', ') + ')' : '';
    return [{ json: { ...dados, textoResposta: 'Anotado: ' + quantity + 'x ' + product.name + obsText + ' ??\nMais alguma coisa ou pode fechar?', chamarLLM: false } }];
  }
  cliente.etapa = 'aguardando_tipo_entrega';
  return [{ json: { ...dados, textoResposta: '�timo! Vai ser entrega ou voc� retira aqui? ??', chamarLLM: false } }];
}

if (cliente.etapa === 'aguardando_tipo_entrega') {
  if (/retir|buscar|pass(o|ar)|l[�a] eu|vou at[e�]|pego|retirad/.test(msg)) {
    cliente.orderState.deliveryType = 'retirada'; cliente.orderState.deliveryFee = 0;
    cliente.etapa = 'aguardando_pagamento';
    return [{ json: { ...dados, textoResposta: 'Retirada anotada ?? Como vai pagar? Dinheiro, PIX ou cart�o?', chamarLLM: false } }];
  }
  cliente.orderState.deliveryType = 'delivery';
  cliente.etapa = 'aguardando_endereco';
  return [{ json: { ...dados, textoResposta: 'Me passa o endere�o completo ?? Rua, n�mero e bairro.', chamarLLM: false } }];
}

if (cliente.etapa === 'aguardando_endereco') {
  if (msg === '__localizacao__' && dados.localizacao) {
    cliente.orderState.gpsLocation = dados.localizacao; cliente.orderState.address = null;
  } else { cliente.orderState.address = msgOrig; cliente.orderState.gpsLocation = null; }
  cliente.orderState.deliveryFee = 0; // TODO: PDV - calcular frete via API
  cliente.etapa = 'aguardando_pagamento';
  return [{ json: { ...dados, textoResposta: 'Endere�o anotado ?? Como vai pagar? Dinheiro, PIX ou cart�o?', chamarLLM: false } }];
}

if (cliente.etapa === 'aguardando_pagamento') {
  let metodo = null;
  if (/pix/.test(msg)) metodo = 'Pix';
  else if (/dinheiro|especie/.test(msg)) metodo = 'Dinheiro';
  else if (/cr[e�]dito/.test(msg)) metodo = 'Cart�o de Cr�dito';
  else if (/d[e�]bito/.test(msg)) metodo = 'Cart�o de D�bito';
  else if (/cart[�a]o/.test(msg)) {
    cliente.etapa = 'aguardando_tipo_cartao';
    return [{ json: { ...dados, textoResposta: 'Cart�o de cr�dito ou d�bito? ??', chamarLLM: false } }];
  }
  if (!metodo) return [{ json: { ...dados, textoResposta: 'Pode pagar com Dinheiro, PIX ou Cart�o (cr�dito/d�bito) - qual prefere? ??', chamarLLM: false } }];
  cliente.orderState.paymentMethod = metodo;
  cliente.orderState.grandTotal = cliente.orderState.itemsTotal + cliente.orderState.deliveryFee;
  cliente.etapa = 'aguardando_confirmacao';
  return [{ json: { ...dados, textoResposta: buildSummary(cliente.orderState) + '\n\nConfirmo o pedido? ??', chamarLLM: false } }];
}

if (cliente.etapa === 'aguardando_tipo_cartao') {
